@pytest.fixture
def unregistered_device_session():
    return <fixture_unregistered_device_session>

@pytest.fixture
def fhir_observation_payload():
    return <fixture_fhir_observation_payload>

def test_unregistered_device_ingest_returns_401(
    unregistered_device_session, fhir_observation_payload
):
    resp = unregistered_device_session.post(
        f"{BASE_URL}/Ingest",
        json=fhir_observation_payload,
    )
    assert resp.status_code == 401, f"Expected 401, got {resp.status_code}"
    body = resp.json()
    issue_text = str(body)
    assert any(
        kw in issue_text.lower()
        for kw in ["unauthorized", "invalid", "certificate", "device"]
    ), f"Unexpected error body: {body}"

import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def registered_device_session():
    return <fixture_registered_device_session>

def _single_obs_bundle():
    obs = <helper_build_fhir_observation>()
    return {
        "resourceType": "Bundle",
        "type": "transaction",
        "entry": [
            {"resource": obs, "request": {"method": "POST", "url": "Observation"}}
        ],
    }

def test_ingest_single_observation_boundary_payload(registered_device_session):
    payload = _single_obs_bundle()
    assert len(payload["entry"]) == 1, "Precondition: bundle must have exactly 1 entry"
    resp = registered_device_session.post(f"{BASE_URL}/Ingest", json=payload)
    assert resp.status_code == 201, f"Expected 201, got {resp.status_code}"
    body = resp.json()
    entries = body.get("entry", [])
    assert len(entries) == 1, f"Expected 1 stored entry, got {len(entries)}"
    obs_id = entries[0].get("resource", {}).get("id")
    assert obs_id
    <helper_cleanup_observation>(obs_id, registered_device_session)
